import hashlib
from adk.sessions import Session

def monitor_session_integrity(session: Session):
    original_hash = hashlib.md5(str(session.state).encode()).hexdigest()

    def check_integrity():
        current_hash = hashlib.md5(str(session.state).encode()).hexdigest()
        if current_hash != original_hash:
            raise Exception("Session state corruption detected!")

    return check_integrity

