from adk import Agent

class SafeAgent(Agent):
    def __init__(self, *args, delegation_blacklist=None, **kwargs):
        super().__init__(*args, **kwargs)
        self.delegation_blacklist = delegation_blacklist or []

    async def _delegate(self, task):
        if self.name in task.call_stack[-3:]:
            return await self._handle_directly(task)

        valid_delegates = [
            agent for agent in self.workflow.agents.values()
            if agent.name not in self.delegation_blacklist
        ]
        return await super()._delegate(task, candidates=valid_delegates)

