def safe_tool_wrapper(func):
    async def wrapper(*args, **kwargs):
        try:
            result = await func(*args, **kwargs)
            return {
                "success": True,
                "data": result,
                "type": func.__name__,
                "timestamp": datetime.now().isoformat()
            }
        except Exception as e:
            return {
                "success": False,
                "error": str(e),
                "type": func.__name__
            }
